/* Element Chalk Variables */
.el-select-dropdown {
  z-index: calc(var(--el-index-top) + 1);
  border-radius: var(--el-border-radius-base);
  box-sizing: border-box;
}
.el-select-dropdown .el-scrollbar.is-empty .el-select-dropdown__list {
  padding: 0;
}

.el-select-dropdown__loading {
  padding: 10px 0;
  margin: 0;
  text-align: center;
  color: var(--el-text-color-secondary);
  font-size: var(--el-select-font-size);
}

.el-select-dropdown__empty {
  padding: 10px 0;
  margin: 0;
  text-align: center;
  color: var(--el-text-color-secondary);
  font-size: var(--el-select-font-size);
}

.el-select-dropdown__wrap {
  max-height: 274px;
}

.el-select-dropdown__list {
  list-style: none;
  padding: 6px 0;
  margin: 0;
  box-sizing: border-box;
}
.el-select-dropdown__list.el-vl__window {
  margin: 6px 0;
  padding: 0;
}

.el-select-dropdown__header {
  padding: 10px;
  border-bottom: 1px solid var(--el-border-color-light);
}

.el-select-dropdown__footer {
  padding: 10px;
  border-top: 1px solid var(--el-border-color-light);
}

.el-select-dropdown__item {
  font-size: var(--el-font-size-base);
  padding: 0 32px 0 20px;
  position: relative;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  color: var(--el-text-color-regular);
  height: 34px;
  line-height: 34px;
  box-sizing: border-box;
  cursor: pointer;
}
.el-select-dropdown__item.is-hovering {
  background-color: var(--el-fill-color-light);
}

.el-select-dropdown__item.is-selected {
  color: var(--el-color-primary);
  font-weight: bold;
}

.el-select-dropdown__item.is-disabled {
  color: var(--el-text-color-placeholder);
  cursor: not-allowed;
  background-color: unset;
}

.el-select-dropdown.is-multiple .el-select-dropdown__item.is-selected::after {
  content: "";
  position: absolute;
  top: 50%;
  right: 20px;
  border-top: none;
  border-right: none;
  background-repeat: no-repeat;
  background-position: center;
  background-color: var(--el-color-primary);
  mask: url("data:image/svg+xml;utf8,%3Csvg class='icon' width='200' height='200' viewBox='0 0 1024 1024' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath fill='currentColor' d='M406.656 706.944L195.84 496.256a32 32 0 10-45.248 45.248l256 256 512-512a32 32 0 00-45.248-45.248L406.592 706.944z'%3E%3C/path%3E%3C/svg%3E") no-repeat;
  mask-size: 100% 100%;
  -webkit-mask: url("data:image/svg+xml;utf8,%3Csvg class='icon' width='200' height='200' viewBox='0 0 1024 1024' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath fill='currentColor' d='M406.656 706.944L195.84 496.256a32 32 0 10-45.248 45.248l256 256 512-512a32 32 0 00-45.248-45.248L406.592 706.944z'%3E%3C/path%3E%3C/svg%3E") no-repeat;
  -webkit-mask-size: 100% 100%;
  transform: translateY(-50%);
  width: 12px;
  height: 12px;
}
.el-select-dropdown.is-multiple .el-select-dropdown__item.is-disabled::after {
  background-color: var(--el-text-color-placeholder);
}

.el-select-group {
  margin: 0;
  padding: 0;
}
.el-select-group__wrap {
  position: relative;
  list-style: none;
  margin: 0;
  padding: 0;
}

.el-select-group__title {
  box-sizing: border-box;
  padding: 0 20px;
  font-size: 12px;
  color: var(--el-color-info);
  line-height: 34px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.el-select-group .el-select-dropdown__item {
  padding-left: 20px;
}

.el-select {
  --el-select-border-color-hover: var(--el-border-color-hover);
  --el-select-disabled-color: var(--el-disabled-text-color);
  --el-select-disabled-border: var(--el-disabled-border-color);
  --el-select-font-size: var(--el-font-size-base);
  --el-select-close-hover-color: var(--el-text-color-secondary);
  --el-select-input-color: var(--el-text-color-placeholder);
  --el-select-multiple-input-color: var(--el-text-color-regular);
  --el-select-input-focus-border-color: var(--el-color-primary);
  --el-select-input-font-size: 14px;
  --el-select-width: 100%;
}

.el-select {
  display: inline-block;
  position: relative;
  vertical-align: middle;
  width: var(--el-select-width);
}
.el-select__wrapper {
  display: flex;
  align-items: center;
  position: relative;
  box-sizing: border-box;
  cursor: pointer;
  text-align: left;
  font-size: 14px;
  padding: 4px 12px;
  gap: 6px;
  min-height: 32px;
  line-height: 24px;
  border-radius: var(--el-border-radius-base);
  background-color: var(--el-fill-color-blank);
  transition: var(--el-transition-duration);
  transform: translate3d(0, 0, 0);
  box-shadow: 0 0 0 1px var(--el-border-color) inset;
}
.el-select__wrapper.is-filterable {
  cursor: text;
}

.el-select__wrapper.is-focused {
  box-shadow: 0 0 0 1px var(--el-color-primary) inset;
}

.el-select__wrapper.is-hovering:not(.is-focused) {
  box-shadow: 0 0 0 1px var(--el-border-color-hover) inset;
}

.el-select__wrapper.is-disabled {
  cursor: not-allowed;
  pointer-events: none;
  background-color: var(--el-fill-color-light);
  color: var(--el-text-color-placeholder);
  box-shadow: 0 0 0 1px var(--el-select-disabled-border) inset;
}
.el-select__wrapper.is-disabled:hover {
  box-shadow: 0 0 0 1px var(--el-select-disabled-border) inset;
}
.el-select__wrapper.is-disabled.is-focus {
  box-shadow: 0 0 0 1px var(--el-input-focus-border-color) inset;
}
.el-select__wrapper.is-disabled .el-select__selected-item {
  color: var(--el-select-disabled-color);
}

.el-select__wrapper.is-disabled .el-select__caret {
  cursor: not-allowed;
}

.el-select__wrapper.is-disabled .el-tag {
  cursor: not-allowed;
}

.el-select__prefix {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  gap: 6px;
  color: var(--el-input-icon-color, var(--el-text-color-placeholder));
}

.el-select__suffix {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  gap: 6px;
  color: var(--el-input-icon-color, var(--el-text-color-placeholder));
}

.el-select__caret {
  color: var(--el-select-input-color);
  font-size: var(--el-select-input-font-size);
  transition: var(--el-transition-duration);
  transform: rotateZ(0deg);
  cursor: pointer;
}
.el-select__caret.is-reverse {
  transform: rotateZ(180deg);
}

.el-select__selection {
  position: relative;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  flex: 1;
  min-width: 0;
  gap: 6px;
}
.el-select__selection.is-near {
  margin-left: -8px;
}

.el-select__selection .el-tag {
  cursor: pointer;
  border-color: transparent;
}
.el-select__selection .el-tag.el-tag--plain {
  border-color: var(--el-tag-border-color);
}
.el-select__selection .el-tag .el-tag__content {
  min-width: 0;
}

.el-select__selected-item {
  display: flex;
  flex-wrap: wrap;
  user-select: none;
}

.el-select__tags-text {
  display: block;
  line-height: normal;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.el-select__placeholder {
  position: absolute;
  z-index: -1;
  display: block;
  top: 50%;
  transform: translateY(-50%);
  width: 100%;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--el-input-text-color, var(--el-text-color-regular));
}
.el-select__placeholder.is-transparent {
  user-select: none;
  color: var(--el-text-color-placeholder);
}

.el-select__popper.el-popper {
  background: var(--el-bg-color-overlay);
  border: 1px solid var(--el-border-color-light);
  box-shadow: var(--el-box-shadow-light);
}
.el-select__popper.el-popper .el-popper__arrow::before {
  border: 1px solid var(--el-border-color-light);
}
.el-select__popper.el-popper[data-popper-placement^=top] .el-popper__arrow::before {
  border-top-color: transparent;
  border-left-color: transparent;
}
.el-select__popper.el-popper[data-popper-placement^=bottom] .el-popper__arrow::before {
  border-bottom-color: transparent;
  border-right-color: transparent;
}
.el-select__popper.el-popper[data-popper-placement^=left] .el-popper__arrow::before {
  border-left-color: transparent;
  border-bottom-color: transparent;
}
.el-select__popper.el-popper[data-popper-placement^=right] .el-popper__arrow::before {
  border-right-color: transparent;
  border-top-color: transparent;
}

.el-select__input-wrapper {
  flex: 1;
}
.el-select__input-wrapper.is-hidden {
  position: absolute;
  opacity: 0;
  z-index: -1;
}

.el-select__input {
  border: none;
  outline: none;
  padding: 0;
  color: var(--el-select-multiple-input-color);
  font-size: inherit;
  font-family: inherit;
  appearance: none;
  height: 24px;
  width: 100%;
  background-color: transparent;
}
.el-select__input.is-disabled {
  cursor: not-allowed;
}

.el-select__input-calculator {
  position: absolute;
  left: 0;
  top: 0;
  max-width: 100%;
  visibility: hidden;
  white-space: pre;
  overflow: hidden;
}

.el-select--large .el-select__wrapper {
  gap: 6px;
  padding: 8px 16px;
  min-height: 40px;
  line-height: 24px;
  font-size: 14px;
}

.el-select--large .el-select__selection {
